import{_ as p,o as a,c as e,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const S=JSON.parse('{"title":"6.五色战队（蓝）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/6.五色战队（蓝）.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/Try another story/6.五色战队（蓝）.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/Try another story/6.五色战队（蓝）.md"};function n(_,b,d,l,i,c){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"_6-五色战队-蓝",tabindex:"-1"},[t("6.五色战队（蓝） "),r("a",{class:"header-anchor",href:"#_6-五色战队-蓝","aria-label":'Permalink to "6.五色战队（蓝）"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="五色战队-蓝" tabindex="-1">五色战队（蓝） <a class="header-anchor" href="#五色战队-蓝" aria-label="Permalink to &quot;五色战队（蓝）&quot;">​</a></h1><p>五色战队（蓝）<br> 出典：《魔法少女小圆》<br> 描述：正传相关的内容，分别是：红，黄，蓝，粉，以及追加的黑，总计五名主要登场的魔法少女的力量，因此下属具有5种不同的技能树。</p><p>概率防御<br> 价格：D+500<br> 类型：被动<br> 描述：有概率降低受到的伤害，只要习得就会发挥效果。<br> 效果：受到攻击时，你进行一个1D10，如果结果大于5，则使你获得5点洞察防御，以及基础洞察防御上的1点附加成功，持续一轮，多次触发效果不叠加。</p><p>升级：挑衅姿态<br> 价格：C+1000<br> 类型：被动<br> 描述：暂时更容易被敌人攻击的姿态，同时被攻击之后有概率降低受到的伤害。<br> 效果：取代概率防御的效果。<br> 你在攻击时可以使被攻击的单位以意志检定豁免出目，若豁免失败，则必须对你进行攻击，但当单位离开超过你身边50米就会失效，这是一个C级心灵来源的胁迫效果。<br> 此外，你在受到伤害时进行一个1D10，若出目大于5，则获得6点洞察防御，同时获得基于洞察防御的1点附加成功，这个加值持续时间是一场景，多次触发不叠加。</p><p>激昂乐章<br> 价格：D+500<br> 动作：自由动作<br> 消耗：2点SG<br> 持续：一场景<br> 描述：上升的光芒令身体活性化，使之能够进行敏捷的运动，让自身的速度上升。<br> 效果：你在基础速度获得等同传奇风度*5米的提升，在闪避防御上获得等同传奇敏捷+1点的提升，多次使用效果不叠加。</p><p>蓄力刺击<br> 价格：D+500<br> 类型：被动<br> 描述：积蓄魔力，增加威力的刺击，以突进破坏敌人的装甲，减少防御能力。<br> 效果：你可以在攻击前支付至多2点SG能量。支付1点时，使你的本次攻击增加3DP加值。<br> 支付2点时，除了获得支付1点的好处外，还能在命中后为敌人附加持续一轮的【破防Ⅰ】。<br> 【破防Ⅰ】：在天生防御/盔甲防御/无名防御上合计减少5点计算，优先减少天生/盔甲防御。</p><p>治愈之音<br> 价格：D+500<br> 动作：迅捷<br> 消耗：1点SG<br> 目标：单一目标<br> 射程：触及距离<br> 描述：用蓝色的光包裹我方队友，治愈伤口。<br> 效果：对于射程范围内的一个友方单位（包括自己）使用，使其获得快速医疗2，持续一轮。<br> 在下次长休息前，这一效果最多治疗合计24点生命值。</p><p>魔剑斩击<br> 价格：C+1000<br> 分类：被动<br> 描述：向挥下剑的尖端聚集魔力，一口气使之破裂的技能，有概率可以无视盔甲防御。<br> 效果：每轮一次，你可以在攻击前进行一个1D10，若结果大于5，则使这次攻击附带【接触攻击】的特性，并且获得2DP的增强加值。<br> 这个效果每生效1次，会减少1点SG能量。</p><p>回击架势<br> 价格：C+1250<br> 动作：迅捷动作<br> 持续：一场景<br> 消耗：6点SG<br> 描述：暂时能给予概率回击的姿态。<br> 效果：处于该状态下，你受到攻击时将造成3点基于闪避防御的反伤，伤害类型为物理-挥砍或穿刺伤害（在购买时选择），同时使自身闪避防御增加5点。<br> 除见证专长外，该架势带来的反伤不能与其他反伤效果同时生效。</p><p>升级：回击剑突<br> 前置：反击架势<br> 价格：B+2000<br> 动作：反射动作<br> 消耗：无<br> 描述：在回击架势下进行反击时发生的招式。<br> 效果：你在处于回击架势下，同时受到攻击才能发动【回击剑突】。<br> 【回击剑突】是一次标准动作进行的近战攻击，可以附带本技能树中所有不超过标准动作使用的招式，且一回合只会发生一次，该效果具有【打断性】。</p><p>剑刃风暴<br> 价格：C+1000<br> 类型：攻击技<br> 动作：整轮动作<br> 消耗：6点SG<br> 射程：见下<br> 范围：见下<br> 描述：一边掀起旋风一边使出回旋斩击，虽然命中有点困难，但威力很高。<br> 效果：<br> 你进行一次普通近战冲锋攻击，攻击中附带等同自身传奇敏捷*1点附加成功。本次冲锋攻击可以进行曲线冲锋，同时攻击冲锋触及范围内的所有敌人。</p><p>你会在这次冲锋经过路径上留下如同飓风一样的影响，等同于你冲锋路径上触及距离范围内会在下一轮开始时，持续时间为一场景，画面表现为你的行动过快，以至于攻击结束后才因为高速移动而在经过路径上掀起了难以遏止的飓风，这是一个C级环境来源的影响。</p><p>【飓风】受影响单位在环境区域内进行远程攻击时，射程减少一半。<br> 环境区域外受影响单位发出的远程攻击经过环境区域计算的距离翻倍。（如：一个不免疫C级环境单位发出的远程攻击在经过范围40米的飓风区域时，按80米计算射程距离。）<br> 受影响单位在环境区域内以嗅觉、听觉进行侦测时，敏感范围提升一半，但受到6DP环境减值。<br> 受影响单位在环境区域内进行的运动检定受到6DP环境减值。</p><p>水妖旋律<br> 价格：C+1500<br> 动作：整轮动作<br> 范围：20米<br> 目标：敌对单位<br> 消耗：6SG<br> 描述：响彻全场的蓝色魔法少女之歌，除了能够给予全体伤害外，还有概率的追加幻惑状态。<br> 效果：<br> 你进行一次普通近战攻击检定，正常造成伤害，同时攻击范围内的所有敌对目标，造成精神伤害。<br> 由于你的歌声仅为一人而鸣，因此在该能力影响范围视为受到【沉默Ⅰ】状态影响。<br> 此外，你攻击前进行一次1D10，若结果大于7，则被攻击命中的单位使用意志豁免伤害出目，失败则陷入【幻惑】状态。</p><p>【幻惑Ⅰ】：处于该状态下的单位无法选择自己攻击的目标，而是对于在场的所有单位进行随机选择。<br> 这是一个C级心灵来源的支配效果，持续时间为一场景。</p><p>【沉默Ⅰ】以使用者为中心影响范围内，所有敌对单位陷入沉默状态，无法通过声音传播信息（如通过听觉进行侦查，使用说话进行交流等），无法满足法术的语言条件，无法进行通过声音传播的社交检定。<br> 即使是范围外的基于声音为媒介的攻击方式与效果，也会在经过范围时被阻断，如同被沉默影响一样。</p><p>浪锋漫舞<br> 价格：C+1250<br> 动作：整轮动作<br> 消耗：6点SG<br> 目标：单一目标<br> 描述：选择一个敌人，用锋刃疾冲攻击时追加更多的攻击，可以重复多次。<br> 效果：<br> 你进行一次普通近战冲锋攻击，本次冲锋攻击无需在基础防御上承受减值，同时本次攻击获得【能量武器】特性。<br> 此外，本次攻击会附带自身传奇敏捷*3点高速，在命中后造成等量的多次攻击减值，画面上如同你进行了多次攻击一样表现。</p><p>刀身爆破<br> 价格：C+1500<br> 动作：标准动作<br> 射程：15+传奇敏捷*10米<br> 消耗：3点SG<br> 范围：见下<br> 描述：用剑进行刺击，射出刀身，在距离足够远的时候爆发的技能。<br> 效果：<br> 你进行一次普通近战攻击检定，对射程范围内的一个指定敌对目标进行攻击，本次攻击会对造成范围伤害，同时对指定目标为中心5米内的所有敌方单位造成攻击，不会造成二次伤害。<br> 这攻击还会在造成伤害后追加等同你的传奇力量*1点韧性伤害，与这次攻击一同处理，只计算一次伤害减免的影响。</p><p>Squartatore<br> 价格：B+2000<br> 动作：迅捷动作<br> 消耗：6点SG<br> 描述：拥有“开膛魔”之名，快速进行多次斩击的技能。是不是稍微有点危险感？by黄色的魔法少女。<br> 效果：<br> 消费一个迅捷动作使用，使自身的下一次攻击获得自身传奇敏捷*3点增强加值，同时附带等同伤害出目的肢体妨碍异常点数，正常豁免可叠加，需要在攻击时选择对哪个肢体效果不良点数。</p><p>无限剑制（非正版）<br> 价格：B+2000<br> 动作：标准动作+移动动作+自由动作<br> 消耗：9点SG<br> 范围：15+决心*5米<br> 目标：见下<br> 持续：一场景<br> 描述：展开心像空间，展开剑斩向全体敌人投掷剑刃的技能，并没有从红色的Archer哪里得到授权，但在游戏中确实有出现这个技能。<br> 效果：<br> 你依次使用标准动作，移动动作，自由动作进行咏唱，每使用一个动作需要支付3点SG，即合计9点，等同消耗需求。</p><p>完成咏唱后，你展开个人心像空间，以你为中心覆盖范围等同于15+决心*5米的场景，所有友方目标（包括自身）将获得加持，获得免疫B级环境影响，以及攻击/防御/三豁免上分别获得7/7/14DP增强加值，你必须在购买时选择其中两种，即攻击或防御，防御或三豁免等，无法全部获得。</p><p>在覆盖范围内，场景只有黑红两色，大地只能看出是插满复数的刀剑的血红色剑冢以及漆黑的无边荒野，血红色的天空中浮现几个漆黑的巨大齿轮，齿轮都被巨大的锁链捆住无法转动，这是一个B级视觉幻象效果，只要接触就会发现场景内的事物并非真实存在。<br> 特殊的是：你可以选择将颜色替换成蓝黑两色，场景替换成演奏厅，地上插着的剑替换成乐器与指挥棒，这取决于你是否希望进行Cosplay，也会影响到你的着装颜色和风格。</p><p>以下是范例咏唱词<br> 标准动作咏唱：<br> 在体はで出来ている.（此身为剑所成）<br> 血潮はで 心は硝子.（血潮如铁 心如琉璃）<br> 几たびの场を越えて不败.（纵横无数战场而不败）<br> 移动动作咏唱：<br> ただ一度の败走もなく.（未尝一次败北）<br> ただ一度の胜利もなし.（亦未得一次胜利）<br> 担い手ここに独り、の丘でを锻つ.（旗手在此孤身一人，铸剑于剑丘之上）<br> 自由动作咏唱：<br> ならば、我が生涯に意味は不要ず.（那么，此生无须任何意义）<br> この体は”无限の”で出来ていた（此身定为“无限之剑”所成）</p><p>千刃之雨<br> 价格：B+2000<br> 前置：无限剑制（非正版）<br> 动作：标准动作<br> 范围：见下<br> 消耗：无<br> 描述：降下剑之雨，最后用巨剑进行突刺的技能，能够大幅度的造成伤害，是只有在无限剑制状态下才能使用的技能。<br> 效果：<br> 这个技能需要在已经展开了无限剑制（非正版）后才能使用。<br> 消费标准动作进行一次普通近战攻击检定，同时攻击无限剑制（非正版）覆盖范围内的所有敌对单位，本次攻击成功数将增加一半。<br> 同时，由于无数的剑环绕在你的身边，你在使用这个技能的一轮内，无需格挡也如同格挡了一样获得格挡带来的好处，这个技能每轮只能使用一次。</p><p>痛觉遮断<br> 价格：A+4000<br> 动作：整轮动作<br> 消耗：14点SG<br> 持续：一场景<br> 目标：自身<br> 描述：切断痛觉，专心反击，可以使受到伤害归零的技能。为什么是归零？这就要问蓝色的魔法少女再生能力有多强了。<br> 效果：启动后，每轮一次，你可以免疫受到的攻击，这是一个A级变形来源的无敌效果。<br> 此外，你会在这一场景中使自身获得传奇耐力*1点快速医疗，每1点提供12点医疗点数，若你没有【坚韧】特性，则在发动技能时额外支付1点意志力，获得【坚韧】特性。 若已有【坚韧】，则在发动技能时额外支付1点意志力，改为【超级坚韧】。</p><p>狂想曲<br> 价格：B+2000<br> 动作：标准动作<br> 消耗：见下<br> 目标：见下<br> 持续：一场景<br> 描述：一定时间内，火力增加的技能，伤害非常之高，而且会追加派生招式【狂虐乱斩】，然而在对于精神状态的负荷相当严重。<br> 效果：<br> 使用本能力后，该场景内你可以使用派生招式【狂虐乱斩】，且发动这一能力时默认执行一次【狂虐乱斩】的效果。无论是否使用这一派生招式，你都会在攻击上额外附带【幻灭】特性，直到持续时间结束后。</p><p>派生招式：狂虐乱斩<br> 描述：引出在灵魂宝石内沉睡的人鱼魔女的一部分力量技能，可以造成大量伤害的同时恢复自身。<br> 效果：消费6点SG，使用一个标准动作，你对触及范围内的一个单位进行一次普通近战攻击，这次攻击附带等同伤害出目的剧痛不良点数，以及【吸血4】。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',29)])])}const D=p(s,[["render",n]]);export{S as __pageData,D as default};
